CREATE TABLE users(id INTEGER PRIMARY KEY AUTOINCREMENT,username TEXT UNIQUE,email TEXT UNIQUE,password TEXT,token TEXT,avatar TEXT,bio TEXT,followers INTEGER DEFAULT 0,likes INTEGER DEFAULT 0,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE videos(id INTEGER PRIMARY KEY AUTOINCREMENT,user_id INTEGER,username TEXT,title TEXT,caption TEXT,video TEXT,thumbnail TEXT,likes INTEGER DEFAULT 0,views INTEGER DEFAULT 0,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE notifications(id INTEGER PRIMARY KEY AUTOINCREMENT,from_user TEXT,to_user TEXT,type TEXT,video_id INTEGER,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);